    </div>
  );
}

client/src/pages/farmer-auth.tsx.content:
import { useState } from "react";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { ArrowLeft, Info, Shield } from "lucide-react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useMutation } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

const step1Schema = z.object({
  username: z.string().min(2, "Name must be at least 2 characters"),
  kissanNumber: z.string().min(10, "Please enter a valid Kissan card number"),
  phone: z.string().min(10, "Please enter a valid phone number"),
});

const step2Schema = z.object({
  bankAccountNumber: z.string().min(9, "Please enter a valid account number"),
  ifscCode: z.string().min(11, "Please enter a valid IFSC code"),
  upiId: z.string().optional(),
});

type Step1Data = z.infer<typeof step1Schema>;
type Step2Data = z.infer<typeof step2Schema>;

export default function FarmerAuth() {
  const [, navigate] = useLocation();
  const [step, setStep] = useState(1);
  const [step1Data, setStep1Data] = useState<Step1Data | null>(null);
  const { toast } = useToast();

  const step1Form = useForm<Step1Data>({
    resolver: zodResolver(step1Schema),
  });

  const step2Form = useForm<Step2Data>({
    resolver: zodResolver(step2Schema),
  });

  const registerMutation = useMutation({
    mutationFn: async (data: any) => {
      const response = await apiRequest("POST", "/api/auth/register", data);
      return response.json();
    },
    onSuccess: (data) => {
      localStorage.setItem("farmconnect-token", data.token);
      localStorage.setItem("farmconnect-user", JSON.stringify(data.user));
      toast({
        title: "Registration Successful!",
        description: "Welcome to FarmConnect. Your farmer account has been created.",
      });
      navigate("/farmer/dashboard");
    },
    onError: (error: any) => {
      toast({
        title: "Registration Failed",
        description: error.message || "Something went wrong. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleStep1Submit = (data: Step1Data) => {
    setStep1Data(data);
    setStep(2);
  };

  const handleStep2Submit = (data: Step2Data) => {
    if (!step1Data) return;

    const registrationData = {
      ...step1Data,
      ...data,
      role: "farmer",
      password: Math.random().toString(36).slice(-8), // Temporary password - in real app, would use proper OTP flow
    };

    registerMutation.mutate(registrationData);
  };

  return (
    <div className="mobile-container">
      <div className="flex flex-col min-h-screen">
        <header className="p-4 border-b border-border">
          <div className="flex items-center space-x-3">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => step === 1 ? navigate("/role") : setStep(1)}
              data-testid="back-button"
            >
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <h1 className="text-lg font-semibold" data-testid="page-title">Farmer Registration</h1>
          </div>
        </header>

        <div className="flex-1 p-6">
          {step === 1 && (
            <div data-testid="farmer-step-1">
              <div className="mb-6">
                <div className="flex items-center space-x-2 mb-4">
                  <div className="w-8 h-8 bg-primary text-primary-foreground rounded-full flex items-center justify-center text-sm font-semibold">
                    1
                  </div>
                  <span className="text-sm text-muted-foreground">Personal Information</span>
                </div>
                <h2 className="text-xl font-semibold mb-2" data-testid="step1-title">Enter Your Details</h2>
                <p className="text-muted-foreground" data-testid="step1-description">We need to verify your farmer identity</p>
              </div>

              <form onSubmit={step1Form.handleSubmit(handleStep1Submit)} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="username">Full Name</Label>
                  <Input
                    id="username"
                    placeholder="Enter your full name"
                    {...step1Form.register("username")}
                    data-testid="input-username"
                  />
                  {step1Form.formState.errors.username && (
                    <p className="text-sm text-destructive">{step1Form.formState.errors.username.message}</p>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="kissanNumber">Kissan Card Number</Label>
                  <Input
                    id="kissanNumber"
                    placeholder="Enter your Kissan card number"
                    {...step1Form.register("kissanNumber")}
                    data-testid="input-kissan-number"
                  />
                  {step1Form.formState.errors.kissanNumber && (
                    <p className="text-sm text-destructive">{step1Form.formState.errors.kissanNumber.message}</p>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="phone">Phone Number</Label>
                  <div className="flex space-x-2">
                    <Select defaultValue="+91">
                      <SelectTrigger className="w-20">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="+91">+91</SelectItem>
                      </SelectContent>
                    </Select>
                    <Input
                      id="phone"
                      placeholder="Enter phone number"
                      className="flex-1"
                      {...step1Form.register("phone")}
                      data-testid="input-phone"
                    />
                  </div>
                  {step1Form.formState.errors.phone && (
                    <p className="text-sm text-destructive">{step1Form.formState.errors.phone.message}</p>
                  )}
                </div>

                <Card className="bg-muted">
                  <CardContent className="p-4">
                    <div className="flex items-start space-x-3">
                      <Info className="h-5 w-5 text-primary mt-1" />
                      <div className="text-sm">
                        <p className="font-medium mb-1">Why do we need this?</p>
                        <p className="text-muted-foreground">Your Kissan card helps us verify you're a registered farmer. We'll send an OTP to your phone for security.</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                <Button type="submit" className="w-full" data-testid="button-send-otp">
                  Send OTP
                </Button>
              </form>
            </div>
          )}

          {step === 2 && (
            <div data-testid="farmer-step-2">
              <div className="mb-6">
                <div className="flex items-center space-x-2 mb-4">
                  <div className="w-8 h-8 bg-primary text-primary-foreground rounded-full flex items-center justify-center text-sm font-semibold">
                    2
                  </div>
                  <span className="text-sm text-muted-foreground">Payment Information</span>
                </div>
                <h2 className="text-xl font-semibold mb-2" data-testid="step2-title">Bank & UPI Details</h2>
                <p className="text-muted-foreground" data-testid="step2-description">Add your payment details to receive money</p>
              </div>

              <form onSubmit={step2Form.handleSubmit(handleStep2Submit)} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="bankAccountNumber">Bank Account Number</Label>
                  <Input
                    id="bankAccountNumber"
                    placeholder="Enter account number"
                    {...step2Form.register("bankAccountNumber")}
                    data-testid="input-bank-account"
                  />
                  {step2Form.formState.errors.bankAccountNumber && (
                    <p className="text-sm text-destructive">{step2Form.formState.errors.bankAccountNumber.message}</p>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="ifscCode">IFSC Code</Label>
                  <Input
                    id="ifscCode"
                    placeholder="Enter IFSC code"
                    {...step2Form.register("ifscCode")}
                    data-testid="input-ifsc-code"
                  />
                  {step2Form.formState.errors.ifscCode && (
                    <p className="text-sm text-destructive">{step2Form.formState.errors.ifscCode.message}</p>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="upiId">UPI ID (Optional)</Label>
                  <Input
                    id="upiId"
                    placeholder="yourname@paytm"
                    {...step2Form.register("upiId")}
                    data-testid="input-upi-id"
                  />
                </div>

                <Card className="bg-muted">
                  <CardContent className="p-4">
                    <div className="flex items-start space-x-3">
                      <Shield className="h-5 w-5 text-primary mt-1" />
                      <div className="text-sm">
                        <p className="font-medium mb-1">Secure & Encrypted</p>
                        <p className="text-muted-foreground">Your payment details are encrypted and secure. We use bank-grade security.</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                <Button 
                  type="submit" 
                  className="w-full" 
                  disabled={registerMutation.isPending}
                  data-testid="button-complete-registration"
                >
                  {registerMutation.isPending ? "Creating Account..." : "Complete Registration"}
                </Button>
              </form>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

client/src/pages/language-selection.tsx.content:
import { useState } from "react";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { useVoice } from "@/hooks/use-voice";
import VoiceAssistant from "@/components/voice-assistant";

const languages = [
  { code: "english", name: "English", flag: "🇺🇸" },
  { code: "hindi", name: "हिंदी (Hindi)", flag: "🇮🇳" },
  { code: "punjabi", name: "ਪੰਜਾਬੀ (Punjabi)", flag: "🌾" },
];

export default function LanguageSelection() {
  const [, navigate] = useLocation();
  const [selectedLanguage, setSelectedLanguage] = useState<string>("");
  const { speak, isSupported } = useVoice();

  // Check if language was already selected
  useState(() => {
    const savedLanguage = localStorage.getItem("farmconnect-language");
    if (savedLanguage) {
      navigate("/role");
    }
  });

  const handleLanguageSelect = (languageCode: string) => {
    setSelectedLanguage(languageCode);

    // Save language preference
    localStorage.setItem("farmconnect-language", languageCode);

    // Speak confirmation
    if (isSupported) {
      const confirmations = {
        english: "English selected. Welcome to FarmConnect!",
        hindi: "हिंदी चुनी गई। फार्मकनेक्ट में आपका स्वागत है!",
        punjabi: "ਪੰਜਾਬੀ ਚੁਣੀ ਗਈ। ਫਾਰਮਕਨੈਕਟ ਵਿੱਚ ਤੁਹਾਡਾ ਸੁਆਗਤ ਹੈ!"
      };
      speak(confirmations[languageCode as keyof typeof confirmations] || confirmations.english);
    }

    // Navigate to role selection after a brief delay
    setTimeout(() => {
      navigate("/role");
    }, 1500);
  };

  const handleVoiceSelect = (languageCode: string) => {
    const language = languages.find(lang => lang.code === languageCode);
    if (language && isSupported) {
      speak(`${language.name} selected. Tap to confirm.`);
    }
  };

  return (
    <div className="mobile-container">
      <div className="flex flex-col items-center justify-center min-h-screen px-6 bg-gradient-to-b from-primary/10 to-background">
        <div className="text-center mb-12">
          <img 
            src="https://images.unsplash.com/photo-1500382017468-9049fed747ef?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&h=600" 
            alt="Agricultural landscape with diverse crops" 
            className="w-32 h-32 mx-auto rounded-full mb-6 shadow-lg object-cover border-4 border-primary/20"
          />
          <h1 className="text-3xl font-bold text-primary mb-2" data-testid="app-title">FarmConnect</h1>
          <p className="text-muted-foreground text-lg" data-testid="app-subtitle">Connecting Farmers & Customers</p>
        </div>

        <div className="w-full max-w-sm space-y-4">
          <h2 className="text-xl font-semibold text-center mb-6" data-testid="language-prompt">Choose Your Language</h2>

          {languages.map((language) => (
            <Button
              key={language.code}
              onClick={() => handleLanguageSelect(language.code)}
              onMouseEnter={() => handleVoiceSelect(language.code)}
              variant="outline"
              className="w-full h-auto p-4 flex items-center justify-between hover:bg-accent hover:text-accent-foreground transition-colors"
              data-testid={`language-${language.code}`}
            >
              <div className="flex items-center space-x-3">
                <span className="text-2xl">{language.flag}</span>
                <span className="font-medium">{language.name}</span>
              </div>
              <VoiceAssistant 
                isActive={selectedLanguage === language.code}
                className="text-muted-foreground voice-indicator"
              />
            </Button>
          ))}
        </div>

        <div className="mt-8 text-center">
          <p className="text-sm text-muted-foreground flex items-center justify-center space-x-2">
            <i className="fas fa-microphone"></i>
            <span data-testid="voice-assistance-text">Voice assistance enabled</span>
          </p>
        </div>
      </div>
    </div>
  );
}

client/src/pages/messages.tsx.content:
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ArrowLeft, MessageCircle } from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { getAuthHeaders } from "@/lib/auth";

export default function Messages() {
  const [, navigate] = useLocation();

  const { data: conversations = [], isLoading } = useQuery({
    queryKey: ["/api/conversations"],
    queryFn: () => fetch("/api/conversations", { headers: getAuthHeaders() }).then(res => res.json()),
  });

  const handleConversationClick = (otherUserId: string) => {
    navigate(`/chat/${otherUserId}`);
  };

  const goBack = () => {
    const user = JSON.parse(localStorage.getItem("farmconnect-user") || "{}");
    if (user.role === "farmer") {
      navigate("/farmer/dashboard");
    } else {
      navigate("/customer/dashboard");
    }
  };

  return (
    <div className="mobile-container">
      <div className="flex flex-col min-h-screen">
        <header className="p-4 border-b border-border bg-card">
          <div className="flex items-center space-x-3">
            <Button
              variant="ghost"
              size="icon"
              onClick={goBack}
              data-testid="back-button"
            >
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <div className="flex-1">
              <h1 className="text-lg font-semibold" data-testid="page-title">Messages</h1>
              <p className="text-sm text-muted-foreground" data-testid="page-subtitle">
                Chat with farmers and customers
              </p>
            </div>
          </div>
        </header>

        <div className="flex-1 p-4">
          {isLoading ? (
            <div className="space-y-3">
              {[1, 2, 3].map((i) => (
                <div key={i} className="bg-card border border-border rounded-lg p-4 animate-pulse">
                  <div className="flex items-center space-x-3">
                    <div className="w-12 h-12 bg-muted rounded-full"></div>
                    <div className="flex-1">
                      <div className="h-4 bg-muted rounded mb-2"></div>
                      <div className="h-3 bg-muted rounded w-2/3"></div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : conversations.length === 0 ? (
            <Card data-testid="empty-conversations-state">
              <CardContent className="p-6 text-center">
                <MessageCircle className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                <h3 className="font-medium mb-2">No conversations yet</h3>
                <p className="text-sm text-muted-foreground">
                  Start chatting with farmers or customers to see your conversations here
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-3">
              {conversations.map((conversation: any) => (
                <Card
                  key={conversation.other_user_id}
                  className="cursor-pointer hover:bg-accent hover:text-accent-foreground transition-colors"
                  onClick={() => handleConversationClick(conversation.other_user_id)}
                  data-testid={`conversation-${conversation.other_user_id}`}
                >
                  <CardContent className="p-4">
                    <div className="flex items-center space-x-3">
                      <img 
                        src={conversation.role === "farmer" 
                          ? "https://images.unsplash.com/photo-1605000797499-95a51c5269ae?ixlib=rb-4.0.3&auto=format&fit=crop&w=100&h=100"
                          : "https://images.unsplash.com/photo-1438761681033-6461ffad8d80?ixlib=rb-4.0.3&auto=format&fit=crop&w=100&h=100"
                        }
                        alt={`${conversation.username} profile`}
                        className="w-12 h-12 rounded-full object-cover"
                        data-testid={`conversation-avatar-${conversation.other_user_id}`}
                      />
                      <div className="flex-1">
                        <div className="flex items-center justify-between mb-1">
                          <h3 className="font-medium" data-testid={`conversation-name-${conversation.other_user_id}`}>
                            {conversation.username}
                          </h3>
                          <span className="text-xs text-muted-foreground" data-testid={`conversation-time-${conversation.other_user_id}`}>
                            {new Date(conversation.last_message_time).toLocaleDateString()}
                          </span>
                        </div>
                        <p className="text-sm text-muted-foreground line-clamp-2" data-testid={`conversation-preview-${conversation.other_user_id}`}>
                          {conversation.last_message || "No messages yet"}
                        </p>
                        <Badge variant="secondary" className="mt-1 text-xs">
                          {conversation.role === "farmer" ? "Farmer" : "Customer"}
                        </Badge>
                      </div>
                      {conversation.unread_count > 0 && (
                        <div className="text-right">
                          <Badge variant="destructive" data-testid={`unread-count-${conversation.other_user_id}`}>
                            {conversation.unread_count}
                          </Badge>
                        </div>
                      )}
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

