client/src/pages/payment.tsx.content:
import { useState, useEffect } from "react";
import { useLocation, useParams } from "wouter";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { ArrowLeft, Shield, Smartphone, University, Banknote, Lock, Copy } from "lucide-react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { loadStripe } from "@stripe/stripe-js";
import { Elements, PaymentElement, useStripe, useElements } from "@stripe/react-stripe-js";

const stripePromise = loadStripe(import.meta.env.VITE_STRIPE_PUBLIC_KEY || "");

interface PaymentParams {
  cropId: string;
}

interface PaymentFormProps {
  crop: any;
  quantity: number;
  totalAmount: number;
  clientSecret: string;
}

function PaymentForm({ crop, quantity, totalAmount, clientSecret }: PaymentFormProps) {
  const stripe = useStripe();
  const elements = useElements();
  const [, navigate] = useLocation();
  const { toast } = useToast();
  const [isProcessing, setIsProcessing] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!stripe || !elements) {
      return;
    }

    setIsProcessing(true);

    try {
      const { error } = await stripe.confirmPayment({
        elements,
        confirmParams: {
          return_url: window.location.origin + "/customer/dashboard",
        },
      });

      if (error) {
        toast({
          title: "Payment Failed",
          description: error.message,
          variant: "destructive",
        });
      } else {
        // Create order record
        await apiRequest("POST", "/api/orders", {
          cropId: crop.id,
          quantity,
          totalPrice: totalAmount,
          status: "completed",
        });

        toast({
          title: "Payment Successful!",
          description: "Your order has been placed successfully.",
        });
        navigate("/customer/dashboard");
      }
    } catch (error: any) {
      toast({
        title: "Payment Error",
        description: error.message || "Something went wrong",
        variant: "destructive",
      });
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <Card>
        <CardContent className="p-6">
          <h3 className="font-semibold mb-4">Payment Details</h3>
          <PaymentElement />
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-4">
          <div className="flex items-start space-x-3">
            <Shield className="h-5 w-5 text-primary mt-1" />
            <div className="text-sm">
              <p className="font-medium mb-1">Secure Transaction</p>
              <p className="text-muted-foreground">
                Your payment is processed securely. Money goes directly to the farmer's account.
              </p>
            </div>
          </div>
        </CardContent>
      </Card>

      <Button
        type="submit"
        className="w-full"
        disabled={!stripe || isProcessing}
        data-testid="pay-button"
      >
        <Lock className="h-4 w-4 mr-2" />
        {isProcessing ? "Processing..." : `Pay ₹${totalAmount} Securely`}
      </Button>
    </form>
  );
}

export default function Payment() {
  const [, navigate] = useLocation();
  const { cropId } = useParams<PaymentParams>();
  const [paymentMethod, setPaymentMethod] = useState("stripe");
  const [upiPin, setUpiPin] = useState("");
  const [clientSecret, setClientSecret] = useState("");
  const { toast } = useToast();

  // Get quantity from URL params
  const urlParams = new URLSearchParams(window.location.search);
  const quantity = parseInt(urlParams.get("quantity") || "1");

  const { data: crop, isLoading } = useQuery({
    queryKey: ["/api/crops", cropId],
    queryFn: () => fetch(`/api/crops/${cropId}`).then(res => res.json()),
    enabled: !!cropId,
  });

  const createPaymentIntentMutation = useMutation({
    mutationFn: async (data: any) => {
      const response = await apiRequest("POST", "/api/create-payment-intent", data);
      return response.json();
    },
    onSuccess: (data) => {
      setClientSecret(data.clientSecret);
    },
    onError: (error: any) => {
      toast({
        title: "Payment Setup Failed",
        description: error.message || "Unable to setup payment",
        variant: "destructive",
      });
    },
  });

  useEffect(() => {
    if (crop && paymentMethod === "stripe") {
      const totalAmount = parseFloat(crop.pricePerUnit) * quantity + 20 + 10; // Add delivery and platform fees
      createPaymentIntentMutation.mutate({
        amount: totalAmount,
        cropId: crop.id,
        quantity,
      });
    }
  }, [crop, paymentMethod, quantity]);

  if (isLoading) {
    return (
      <div className="mobile-container">
        <div className="flex items-center justify-center min-h-screen">
          <div className="animate-spin w-8 h-8 border-4 border-primary border-t-transparent rounded-full" />
        </div>
      </div>
    );
  }

  if (!crop) {
    return (
      <div className="mobile-container">
        <div className="flex flex-col items-center justify-center min-h-screen p-6">
          <h1 className="text-xl font-semibold mb-2">Product Not Found</h1>
          <Button onClick={() => navigate("/customer/dashboard")}>
            Back to Dashboard
          </Button>
        </div>
      </div>
    );
  }

  const subtotal = parseFloat(crop.pricePerUnit) * quantity;
  const deliveryFee = 20;
  const platformFee = 10;
  const totalAmount = subtotal + deliveryFee + platformFee;

  const handleCopyUPI = () => {
    navigator.clipboard.writeText("farmer.upi@example");
    toast({
      title: "UPI ID Copied",
      description: "The farmer's UPI ID has been copied to clipboard",
    });
  };

  return (
    <div className="mobile-container">
      <div className="flex flex-col min-h-screen">
        <header className="p-4 border-b border-border bg-card">
          <div className="flex items-center space-x-3">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => navigate(`/product/${cropId}`)}
              data-testid="back-button"
            >
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <h1 className="text-lg font-semibold" data-testid="page-title">Secure Payment</h1>
          </div>
        </header>

        <div className="flex-1 p-4 space-y-6">
          {/* Order Summary */}
          <Card data-testid="order-summary">
            <CardHeader>
              <CardTitle className="text-base">Order Summary</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center space-x-3">
                <img
                  src={crop.images?.[0] || "https://images.unsplash.com/photo-1546470427-e2a45bcd0c8c?ixlib=rb-4.0.3&auto=format&fit=crop&w=100&h=100"}
                  alt={crop.name}
                  className="w-16 h-16 rounded-lg object-cover"
                  data-testid="order-product-image"
                />
                <div className="flex-1">
                  <h4 className="font-medium" data-testid="order-product-name">{crop.name}</h4>
                  <p className="text-sm text-muted-foreground" data-testid="order-farmer">
                    By Farmer {crop.farmerId.slice(0, 8)}...
                  </p>
                  <p className="text-sm" data-testid="order-quantity">
                    Quantity: {quantity} {crop.unit}
                  </p>
                </div>
                <span className="font-semibold text-lg" data-testid="order-subtotal">
                  ₹{subtotal.toFixed(2)}
                </span>
              </div>

              <div className="border-t border-border pt-3 space-y-2">
                <div className="flex justify-between text-sm">
                  <span>Subtotal</span>
                  <span data-testid="subtotal-amount">₹{subtotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span>Delivery Fee</span>
                  <span data-testid="delivery-fee">₹{deliveryFee}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span>Platform Fee</span>
                  <span data-testid="platform-fee">₹{platformFee}</span>
                </div>
                <div className="flex justify-between font-semibold text-lg border-t border-border pt-2">
                  <span>Total</span>
                  <span data-testid="total-amount">₹{totalAmount.toFixed(2)}</span>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Payment Methods */}
          <Card data-testid="payment-methods">
            <CardHeader>
              <CardTitle className="text-base">Payment Method</CardTitle>
            </CardHeader>
            <CardContent>
              <RadioGroup value={paymentMethod} onValueChange={setPaymentMethod}>
                <div className="flex items-center space-x-3 p-3 border border-border rounded-lg">
                  <RadioGroupItem value="stripe" id="stripe" />
                  <Label htmlFor="stripe" className="flex items-center space-x-3 flex-1 cursor-pointer">
                    <Smartphone className="h-5 w-5 text-primary" />
                    <div>
                      <span className="font-medium">Card Payment</span>
                      <p className="text-xs text-muted-foreground">Pay securely with your card</p>
                    </div>
                  </Label>
                </div>

                <div className="flex items-center space-x-3 p-3 border border-border rounded-lg">
                  <RadioGroupItem value="upi" id="upi" />
                  <Label htmlFor="upi" className="flex items-center space-x-3 flex-1 cursor-pointer">
                    <University className="h-5 w-5 text-primary" />
                    <div>
                      <span className="font-medium">UPI Payment</span>
                      <p className="text-xs text-muted-foreground">Pay directly to farmer's UPI</p>
                    </div>
                  </Label>
                </div>

                <div className="flex items-center space-x-3 p-3 border border-border rounded-lg">
                  <RadioGroupItem value="cod" id="cod" />
                  <Label htmlFor="cod" className="flex items-center space-x-3 flex-1 cursor-pointer">
                    <Banknote className="h-5 w-5 text-primary" />
                    <div>
                      <span className="font-medium">Cash on Delivery</span>
                      <p className="text-xs text-muted-foreground">Pay when you receive</p>
                    </div>
                  </Label>
                </div>
              </RadioGroup>
            </CardContent>
          </Card>

          {/* Payment Forms */}
          {paymentMethod === "stripe" && clientSecret && (
            <Elements stripe={stripePromise} options={{ clientSecret }}>
              <PaymentForm
                crop={crop}
                quantity={quantity}
                totalAmount={totalAmount}
                clientSecret={clientSecret}
              />
            </Elements>
          )}

          {paymentMethod === "upi" && (
            <div className="space-y-4">
              <Card>
                <CardContent className="p-4 space-y-4">
                  <div>
                    <Label className="text-sm font-medium">Farmer's UPI ID</Label>
                    <div className="bg-muted p-3 rounded-lg flex items-center justify-between mt-2">
                      <span className="font-mono text-sm" data-testid="farmer-upi-id">
                        farmer.upi@example
                      </span>
                      <Button variant="ghost" size="sm" onClick={handleCopyUPI}>
                        <Copy className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>

                  <div>
                    <Label htmlFor="upiPin" className="text-sm font-medium">Your UPI PIN</Label>
                    <Input
                      id="upiPin"
                      type="password"
                      placeholder="Enter 4-digit UPI PIN"
                      maxLength={4}
                      value={upiPin}
                      onChange={(e) => setUpiPin(e.target.value)}
                      className="text-center text-lg tracking-widest mt-2"
                      data-testid="upi-pin-input"
                    />
                  </div>
                </CardContent>
              </Card>

              <Button className="w-full" data-testid="pay-upi-button">
                <Lock className="h-4 w-4 mr-2" />
                Pay ₹{totalAmount.toFixed(2)} via UPI
              </Button>
            </div>
          )}

          {paymentMethod === "cod" && (
            <Card>
              <CardContent className="p-4">
                <div className="text-center space-y-4">
                  <Banknote className="h-12 w-12 text-primary mx-auto" />
                  <div>
                    <h3 className="font-medium">Cash on Delivery</h3>
                    <p className="text-sm text-muted-foreground mt-2">
                      You will pay ₹{totalAmount.toFixed(2)} when the order is delivered to you.
                    </p>
                  </div>
                  <Button className="w-full" data-testid="confirm-cod-button">
                    Confirm Order
                  </Button>
                </div>
              </CardContent>
            </Card>
          )}
        </div>
      </div>
    </div>
  );
}

client/src/pages/product-detail.tsx.content:
import { useState } from "react";
import { useLocation, useParams } from "wouter";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { ArrowLeft, Heart, Star, MapPin, Phone, MessageCircle, ShoppingCart, Minus, Plus } from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";

interface ProductDetailParams {
  id: string;
}

export default function ProductDetail() {
  const [, navigate] = useLocation();
  const { id } = useParams<ProductDetailParams>();
  const [quantity, setQuantity] = useState(1);
  const [isFavorite, setIsFavorite] = useState(false);
  const { toast } = useToast();

  const { data: crop, isLoading } = useQuery({
    queryKey: ["/api/crops", id],
    queryFn: () => fetch(`/api/crops/${id}`).then(res => res.json()),
    enabled: !!id,
  });

  const { data: reviews = [] } = useQuery({
    queryKey: ["/api/reviews/crop", id],
    queryFn: () => fetch(`/api/reviews/crop/${id}`).then(res => res.json()),
    enabled: !!id,
  });

  if (isLoading) {
    return (
      <div className="mobile-container">
        <div className="flex flex-col min-h-screen">
          <div className="animate-pulse">
            <div className="h-64 bg-muted"></div>
            <div className="p-4 space-y-4">
              <div className="h-8 bg-muted rounded"></div>
              <div className="h-4 bg-muted rounded w-2/3"></div>
              <div className="h-20 bg-muted rounded"></div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (!crop) {
    return (
      <div className="mobile-container">
        <div className="flex flex-col items-center justify-center min-h-screen p-6">
          <h1 className="text-xl font-semibold mb-2">Product Not Found</h1>
          <p className="text-muted-foreground mb-4">The product you're looking for doesn't exist.</p>
          <Button onClick={() => navigate("/customer/dashboard")}>
            Back to Dashboard
          </Button>
        </div>
      </div>
    );
  }

  const handleQuantityChange = (delta: number) => {
    const newQuantity = Math.max(1, Math.min(crop.quantity, quantity + delta));
    setQuantity(newQuantity);
  };

  const handleBuyNow = () => {
    navigate(`/payment/${crop.id}?quantity=${quantity}`);
  };

  const handleContactFarmer = () => {
    navigate(`/chat/${crop.farmerId}`);
  };

  const toggleFavorite = () => {
    setIsFavorite(!isFavorite);
    toast({
      title: isFavorite ? "Removed from favorites" : "Added to favorites",
      description: isFavorite ? "Product removed from your favorites" : "Product added to your favorites",
    });
  };

  const totalPrice = (parseFloat(crop.pricePerUnit) * quantity).toFixed(2);
  const averageRating = reviews.length > 0 
    ? (reviews.reduce((sum: number, review: any) => sum + review.rating, 0) / reviews.length).toFixed(1)
    : "0.0";

  return (
    <div className="mobile-container">
      <div className="flex flex-col min-h-screen">
        <header className="relative">
          <img 
            src={crop.images?.[0] || "https://images.unsplash.com/photo-1546470427-e2a45bcd0c8c?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&h=600"} 
            alt={crop.name}
            className="w-full h-64 object-cover"
            data-testid="product-image"
          />
          <div className="absolute top-4 left-4">
            <Button
              variant="secondary"
              size="icon"
              className="bg-black/50 text-white hover:bg-black/70"
              onClick={() => navigate("/customer/dashboard")}
              data-testid="back-button"
            >
              <ArrowLeft className="h-5 w-5" />
            </Button>
          </div>
          <div className="absolute top-4 right-4">
            <Button
              variant="secondary"
              size="icon"
              className="bg-black/50 text-white hover:bg-black/70"
              onClick={toggleFavorite}
              data-testid="favorite-button"
            >
              <Heart className={`h-5 w-5 ${isFavorite ? "fill-current" : ""}`} />
            </Button>
          </div>
        </header>

        <div className="flex-1 p-4 space-y-6">
          {/* Product Info */}
          <div>
            <div className="flex items-start justify-between mb-2">
              <h1 className="text-2xl font-bold" data-testid="product-name">{crop.name}</h1>
              <span className="text-2xl font-bold text-accent" data-testid="product-price">
                ₹{crop.pricePerUnit}/{crop.unit}
              </span>
            </div>
            <div className="flex items-center space-x-4 text-sm text-muted-foreground mb-4">
              <div className="flex items-center space-x-1">
                <Star className="h-4 w-4 text-yellow-500" />
                <span data-testid="product-rating">{averageRating}</span>
                <span>({reviews.length} reviews)</span>
              </div>
              <div className="flex items-center space-x-1">
                <MapPin className="h-4 w-4 text-primary" />
                <span data-testid="product-distance">2.3 km away</span>
              </div>
            </div>
            {crop.description && (
              <p className="text-muted-foreground" data-testid="product-description">
                {crop.description}
              </p>
            )}
          </div>

          {/* Farmer Info */}
          <Card data-testid="farmer-info">
            <CardContent className="p-4">
              <h3 className="font-semibold mb-3">Farmer Details</h3>
              <div className="flex items-center space-x-3">
                <img 
                  src="https://images.unsplash.com/photo-1605000797499-95a51c5269ae?ixlib=rb-4.0.3&auto=format&fit=crop&w=100&h=100" 
                  alt="Farmer profile" 
                  className="w-12 h-12 rounded-full object-cover"
                  data-testid="farmer-avatar"
                />
                <div className="flex-1">
                  <h4 className="font-medium" data-testid="farmer-name">Farmer {crop.farmerId.slice(0, 8)}...</h4>
                  <p className="text-sm text-muted-foreground" data-testid="farmer-location">Local Farm</p>
                  <div className="flex items-center space-x-1 mt-1">
                    <Star className="h-3 w-3 text-yellow-500" />
                    <span className="text-sm" data-testid="farmer-rating">4.9</span>
                    <span className="text-xs text-muted-foreground">(127 reviews)</span>
                  </div>
                </div>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleContactFarmer}
                  data-testid="chat-farmer-button"
                >
                  <MessageCircle className="h-4 w-4 mr-2" />
                  Chat
                </Button>
              </div>
            </CardContent>
          </Card>

          {/* Quantity & Availability */}
          <Card data-testid="quantity-selection">
            <CardContent className="p-4">
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-semibold">Availability</h3>
                <Badge variant="secondary" data-testid="stock-status">
                  {crop.quantity} {crop.unit} available
                </Badge>
              </div>
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  <span className="text-sm">Quantity:</span>
                  <div className="flex items-center space-x-2">
                    <Button
                      variant="outline"
                      size="icon"
                      className="h-8 w-8"
                      onClick={() => handleQuantityChange(-1)}
                      disabled={quantity <= 1}
                      data-testid="decrease-quantity"
                    >
                      <Minus className="h-4 w-4" />
                    </Button>
                    <Input
                      type="number"
                      value={quantity}
                      onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                      className="w-16 text-center"
                      min="1"
                      max={crop.quantity}
                      data-testid="quantity-input"
                    />
                    <Button
                      variant="outline"
                      size="icon"
                      className="h-8 w-8"
                      onClick={() => handleQuantityChange(1)}
                      disabled={quantity >= crop.quantity}
                      data-testid="increase-quantity"
                    >
                      <Plus className="h-4 w-4" />
                    </Button>
                  </div>
                  <span className="text-sm text-muted-foreground">{crop.unit}</span>
                </div>
                <div className="text-right">
                  <p className="text-lg font-semibold" data-testid="total-price">₹{totalPrice}</p>
                  <p className="text-xs text-muted-foreground">Total</p>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Customer Reviews */}
          {reviews.length > 0 && (
            <div data-testid="reviews-section">
              <h3 className="font-semibold mb-4">Customer Reviews</h3>
              <div className="space-y-4">
                {reviews.slice(0, 3).map((review: any) => (
                  <div key={review.id} className="border-b border-border pb-4 last:border-0">
                    <div className="flex items-start space-x-3">
                      <img 
                        src="https://images.unsplash.com/photo-1438761681033-6461ffad8d80?ixlib=rb-4.0.3&auto=format&fit=crop&w=100&h=100" 
                        alt="Customer profile" 
                        className="w-10 h-10 rounded-full object-cover"
                        data-testid={`review-avatar-${review.id}`}
                      />
                      <div className="flex-1">
                        <div className="flex items-center space-x-2 mb-1">
